  if(!enif_get_list_length(env, argv[0], &str_idLen)) Badarg(2516,"str_id");
  str_id = (wxChar *) enif_alloc(sizeof(wxChar)*str_idLen);
  str_id_ptr = str_id;
  str_idTail = argv[0];
  while(!enif_is_empty_list(env, str_idTail)) {
    if(!enif_get_list_cell(env, str_idTail, &str_idHead, &str_idTail)) Badarg(2516,"str_id");
    if(!enif_get_int(env, str_idHead, &str_id_tmp)) Badarg(2516,"str_id");
    *str_id_ptr = (wxChar) str_id_tmp;
    str_id_ptr++;
  };
  ERL_NIF_TERM lstHead, lstTail;
  lstTail = argv[1];
  if(!enif_is_list(env, lstTail)) Badarg(2516,"Options");
  const ERL_NIF_TERM *tpl;
