// wxStyledTextCtrl::MarkerDefine
void wxStyledTextCtrl_MarkerDefine(WxeApp *app, wxeCommand& Ecmd)
{
  wxColour foreground= wxNullColour;
  wxColour background= wxNullColour;
  wxeMemEnv *memenv = Ecmd.memenv;
  ErlNifEnv *env = Ecmd.env;
  ERL_NIF_TERM * argv = Ecmd.args;
  wxStyledTextCtrl *This;
  This = (wxStyledTextCtrl *) memenv->getPtr(env, argv[0], "This");
  int markerNumber;
  if(!enif_get_int(env, argv[1], &markerNumber)) Badarg(3020,"markerNumber"); // int
  int markerSymbol;
  if(!enif_get_int(env, argv[2], &markerSymbol)) Badarg(3020,"markerSymbol"); // int
  ERL_NIF_TERM lstHead, lstTail;
  lstTail = argv[3];
  if(!enif_is_list(env, lstTail)) Badarg(3020,"Options");
  const ERL_NIF_TERM *tpl;
  int tpl_sz;
  while(!enif_is_empty_list(env, lstTail)) {
    if(!enif_get_list_cell(env, lstTail, &lstHead, &lstTail)) Badarg(3020,"Options");
    if(!enif_get_tuple(env, lstHead, &tpl_sz, &tpl) || tpl_sz != 2) Badarg(3020,"Options");
    if(enif_is_identical(tpl[0], enif_make_atom(env, "foreground"))) {
  const ERL_NIF_TERM *foreground_t;
  int foreground_sz;
  if(!enif_get_tuple(env, tpl[1], &foreground_sz, &foreground_t)) Badarg(3020,"foreground");
  int foregroundR;
  if(!enif_get_int(env, foreground_t[0], &foregroundR)) Badarg(3020,"foreground");
  int foregroundG;
  if(!enif_get_int(env, foreground_t[1], &foregroundG)) Badarg(3020,"foreground");
  int foregroundB;
  if(!enif_get_int(env, foreground_t[2], &foregroundB)) Badarg(3020,"foreground");
  int foregroundA;
  if(!enif_get_int(env, foreground_t[3], &foregroundA)) Badarg(3020,"foreground");
  foreground = wxColour(foregroundR,foregroundG,foregroundB,foregroundA);
    } else     if(enif_is_identical(tpl[0], enif_make_atom(env, "background"))) {
  const ERL_NIF_TERM *background_t;
  int background_sz;
  if(!enif_get_tuple(env, tpl[1], &background_sz, &background_t)) Badarg(3020,"background");
  int backgroundR;
  if(!enif_get_int(env, background_t[0], &backgroundR)) Badarg(3020,"background");
  int backgroundG;
  if(!enif_get_int(env, background_t[1], &backgroundG)) Badarg(3020,"background");
  int backgroundB;
  if(!enif_get_int(env, background_t[2], &backgroundB)) Badarg(3020,"background");
  int backgroundA;
  if(!enif_get_int(env, background_t[3], &backgroundA)) Badarg(3020,"background");
  background = wxColour(backgroundR,backgroundG,backgroundB,backgroundA);
    } else        Badarg(3020,"Options");
  };
  if(!This) throw wxe_badarg("This");
  This->MarkerDefine(markerNumber,markerSymbol,foreground,background);

}

